import{c as n,Q as e,j as s,m as i}from"./chunks/framework.BPKcPtvA.js";const k=JSON.parse('{"title":"Analiza Koda & Otisak Sistema","description":"Tehnički pregled repozitorijuma, modulskih zavisnosti i orkestracione strukture","frontmatter":{"title":"Analiza Koda & Otisak Sistema","description":"Tehnički pregled repozitorijuma, modulskih zavisnosti i orkestracione strukture","keywords":"codebase analysis, folder structure, python dependency, code architecture","robots":"index, follow"},"headers":[],"relativePath":"analysis.md","filePath":"analysis.md","lastUpdated":null}'),t={name:"analysis.md"};function o(r,a,p,l,d,c){return e(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="📊-analiza-koda-otisak-sistema" tabindex="-1">📊 Analiza Koda &amp; Otisak Sistema <a class="header-anchor" href="#📊-analiza-koda-otisak-sistema" aria-label="Permalink to &quot;📊 Analiza Koda &amp; Otisak Sistema&quot;">​</a></h1><p>Dokumentacija sprovodi detaljan arhitektonski i strukturni pregled koda projekta <strong>AI Workflow Orchestrator</strong>.</p><p>Ceo sistem je projektovan kao Python monolitski repozitorijum sa modularno razdvojenim slojevima odgovornosti, prateći nulto-poverenje (Zero-Trust) i visoku auditabilnost.</p><hr><h2 id="📂-struktura-direktorijuma-system-footprint" tabindex="-1">📂 Struktura Direktorijuma (System Footprint) <a class="header-anchor" href="#📂-struktura-direktorijuma-system-footprint" aria-label="Permalink to &quot;📂 Struktura Direktorijuma (System Footprint)&quot;">​</a></h2><p>Sledeći dijagram prikazuje kompletnu strukturu direktorijuma repozitorijuma i svrhu svakog od modula:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ai-workflow-orchestrator/</span></span>
<span class="line"><span>├── main.py                    # CLI ulazna tačka sistema (enforce_identity + WorkflowOrchestrator)</span></span>
<span class="line"><span>├── requirements.txt           # Definicije spoljnih biblioteka (FastAPI, google-genai, pymongo, sqlite3)</span></span>
<span class="line"><span>├── prd.md                     # Definicija zahteva proizvoda (Product Requirements Document)</span></span>
<span class="line"><span>├── SUBMISSION.md              # Zvanični dokument za Rapid Agent Hackathon predaju</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── core/                      # Osnovne deljene definicije i sigurnosni slojevi</span></span>
<span class="line"><span>│   ├── types.py               # Enumi za AgentRole, AgentMode, DebateOutcome, Argument</span></span>
<span class="line"><span>│   ├── identity.py            # IdentityGuard (Zero-trust provera za sixth-hawk-492717-m1)</span></span>
<span class="line"><span>│   └── key_manager.py         # KeyManager za rotiranje i upravljanje API ključevima</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── orchestrator/              # Glavni orkestracioni mozak</span></span>
<span class="line"><span>│   ├── engine.py              # WorkflowOrchestrator (11-stepeni orkestracioni pipeline)</span></span>
<span class="line"><span>│   └── router.py              # ModelRouter za Vertex AI / Gemini modele (gemini-2.5-flash)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── debate/                    # Mašina za multi-agent debatu (Adversarial Layer)</span></span>
<span class="line"><span>│   ├── rounds.py              # DebateManager (Upravljanje rundama i &quot;Rule of 3&quot; rafinacijom)</span></span>
<span class="line"><span>│   └── aggregator.py          # DebateAggregator (Izračunavanje konsenzusa, konflikata i ELO ratinga)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── agents/                    # Specijalizovane agent agenture</span></span>
<span class="line"><span>│   ├── base_agent.py          # BaseAgent sa podrškom za EXECUTION i DEBATE režime rada</span></span>
<span class="line"><span>│   ├── factory.py             # AgentFactory (Dinamičko kreiranje instanci agenata)</span></span>
<span class="line"><span>│   └── [specialized].py       # Analyst, Solution, Critic, Security, Optimizer, Aggregator agenti</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── memory/                    # Dugoročno i kratkoročno pamćenje (Memory Layer)</span></span>
<span class="line"><span>│   ├── database.py            # Database (SQLite perzistencija, istorija odluka, ELO tabela)</span></span>
<span class="line"><span>│   └── mongodb_atlas.py       # MongoDB Atlas integracija (Vektorska pretraga i agregacija e-reputacije)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── execution/                 # Modul za bezbedno izvršenje planova</span></span>
<span class="line"><span>│   ├── manager.py             # ExecutionManager (Koordinacija izvršenja i Rollback sekvenca)</span></span>
<span class="line"><span>│   └── runner.py              # ExecutionRunner (Pokretanje CLI/SQL operacija uz sandboxing)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── validation/                # Provera rezultata nakon izvršenja</span></span>
<span class="line"><span>│   └── checker.py             # ValidationChecker (Verifikacija ispravnosti i formiranje izveštaja)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── security/                  # Dodatni sigurnosni mehanizmi</span></span>
<span class="line"><span>│   └── token_budget.py        # TokenBudgetTracker i TokenBudgetMiddleware (Circuit Breaker na 100k tokena)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── observability/             # Nadgledanje i samoisceljenje</span></span>
<span class="line"><span>│   └── self_heal_hook.py      # Autonomni mehanizam za popravku neuspelih operacija na nivou OS</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── api/                       # FastAPI Web Interfejs</span></span>
<span class="line"><span>│   ├── routes.py              # HTTP rute za pokretanje workflow-a i pretragu memorije</span></span>
<span class="line"><span>│   └── status_manager.py      # JobStatusManager za real-time strimovanje stanja preko SSE</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── dashboard/                 # Frontend Web Kontrolna Tabla</span></span>
<span class="line"><span>│   └── index.html             # Premium Glassmorphism UI (Tailwind + CSS mikro-animacije)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── tests/                     # Testni paket (PyTest)</span></span>
<span class="line"><span>    ├── test_agents.py         # Verifikacija model generisanja i ponašanja agenata</span></span>
<span class="line"><span>    ├── test_elo.py            # Simulacija ELO promena tokom debata</span></span>
<span class="line"><span>    └── test_circuit_breaker.py # Provera okidanja token barijere</span></span></code></pre></div><hr><h2 id="⚙️-analiza-glavnih-modula-i-zavisnosti" tabindex="-1">⚙️ Analiza Glavnih Modula i Zavisnosti <a class="header-anchor" href="#⚙️-analiza-glavnih-modula-i-zavisnosti" aria-label="Permalink to &quot;⚙️ Analiza Glavnih Modula i Zavisnosti&quot;">​</a></h2><p>Sistem se oslanja na čist prenos stanja između modula bez cikličnih zavisnosti:</p><table tabindex="0"><thead><tr><th>Modul</th><th>Primarna Odgovornost</th><th>Ključne Zavisnosti</th></tr></thead><tbody><tr><td><strong><code>core.identity</code></strong></td><td>Sigurnosna nulta verifikacija pre bilo koje operacije.</td><td>Bez spoljnih zavisnosti (čita <code>os.environ</code>).</td></tr><tr><td><strong><code>orchestrator.engine</code></strong></td><td>Upravlja 11-stepenim tokom izvršenja od učitavanja memorije do audita.</td><td><code>debate</code>, <code>execution</code>, <code>validation</code>, <code>memory</code>, <code>core.identity</code>.</td></tr><tr><td><strong><code>debate.rounds</code></strong></td><td>Vodi strukturisanu konfrontaciju argumenata u rundama.</td><td><code>agents.factory</code>, <code>debate.aggregator</code>, <code>memory.database</code>.</td></tr><tr><td><strong><code>memory.database</code></strong></td><td>SQLite perzistencija odluka i istorijskog konteksta.</td><td><code>core.types</code>, <code>sqlite3</code>.</td></tr><tr><td><strong><code>memory.mongodb_atlas</code></strong></td><td>Vektorska pretraga konflikata i globalni audit.</td><td><code>pymongo.MongoClient</code>.</td></tr><tr><td><strong><code>execution.manager</code></strong></td><td>Izvršava odobreni plan i po potrebi radi <strong>Rollback</strong> unazad.</td><td><code>execution.runner</code>.</td></tr><tr><td><strong><code>security.token_budget</code></strong></td><td>Sprečava beskonačne LLM petlje i finansijsko probijanje.</td><td>Singleton obrazac za celokupnu sesiju.</td></tr></tbody></table><hr><h2 id="🔒-sigurnosni-standardi-koda" tabindex="-1">🔒 Sigurnosni Standardi Koda <a class="header-anchor" href="#🔒-sigurnosni-standardi-koda" aria-label="Permalink to &quot;🔒 Sigurnosni Standardi Koda&quot;">​</a></h2><p>Primenjeni su strogi sigurnosni principi:</p><ol><li><strong>Nema curenja tokena:</strong> <code>TokenBudgetTracker</code> sprečava sesije sa više od <code>100,000</code> tokena. Svaki poziv ka <code>aio.models.generate_content</code> se registruje i odbija ukoliko je budžet prekoračen.</li><li><strong>Admission Control:</strong> <code>ExecutionRunner</code> u [runner.py:30-56](file:///home/kizabgd/.gemini/extensions/ai-workflow-orchestrator/execution/runner.py#L30-L56) skenira komande i blokira priviligovane kubernetes kontejnere, SQL injekcije i montiranje docker sock-a na nivou statičke analize pre izvršenja naredbe.</li><li><strong>Auditabilni Reasoning Chain:</strong> Svaki korak je povezan sa <code>trace_id</code> (UUIDv4) i memorijski je perzistentan, omogućavajući 100% determinističku rekonstrukciju debate.</li></ol>`,15)])])}const m=n(t,[["render",o]]);export{k as __pageData,m as default};
